    /**
     * @method
     * @name mexc#fetchStatus
     * @description the latest known information on the availability of the exchange API
     * @see https://www.mexc.com/api-docs/spot-v3/market-data-endpoints/test-connectivity // spot
     * @see https://www.mexc.com/api-docs/futures/market-endpoints/get-server-time // swap
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [status structure]{@link https://docs.ccxt.com/?id=exchange-status-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchStatus(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            var marketTypequeryVariable = this.handleMarketTypeAndParams("fetchStatus", null, parameters);
            var marketType = ((java.util.List<Object>) marketTypequeryVariable).get(0);
            var query = ((java.util.List<Object>) marketTypequeryVariable).get(1);
            Object response = new java.util.HashMap<String, Object>() {{}};
            Object status = null;
            Object updated = null;
            if (Helpers.isTrue(Helpers.isEqual(marketType, "spot")))
            {
                response = (this.spotPublicGetPing(query)).join();
                //
                //     {}
                //
                Object keys = Helpers.objectKeys(response);
                Object length = Helpers.getArrayLength(keys);
                status = ((Helpers.isTrue(length))) ? this.json(response) : "ok";
            } else if (Helpers.isTrue(Helpers.isEqual(marketType, "swap")))
            {
                response = (this.contractPublicGetPing(query)).join();
                //
                //     {"success":true,"code":"0","data":"1648124374985"}
                //
                status = ((Helpers.isTrue(this.safeValue(response, "success")))) ? "ok" : this.json(response);
                updated = this.safeInteger(response, "data");
            }
            final Object finalStatus = status;
            final Object finalUpdated = updated;
            final Object finalResponse = response;
            return new java.util.HashMap<String, Object>() {{
                put( "status", finalStatus );
                put( "updated", finalUpdated );
                put( "url", null );
                put( "eta", null );
                put( "info", finalResponse );
            }};
        });

    }

    /**
     * @method
     * @name mexc#fetchTime
     * @description fetches the current integer timestamp in milliseconds from the exchange server
     * @see https://www.mexc.com/api-docs/spot-v3/market-data-endpoints/check-server-time // spot
     * @see https://www.mexc.com/api-docs/futures/market-endpoints/get-server-time // swap
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {int} the current integer timestamp in milliseconds from the exchange server
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTime(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            var marketTypequeryVariable = this.handleMarketTypeAndParams("fetchTime", null, parameters);
            var marketType = ((java.util.List<Object>) marketTypequeryVariable).get(0);
            var query = ((java.util.List<Object>) marketTypequeryVariable).get(1);
            Object response = null;
            if (Helpers.isTrue(Helpers.isEqual(marketType, "spot")))
            {
                response = (this.spotPublicGetTime(query)).join();
                //
                //     {"serverTime": "1647519277579"}
                //
                return this.safeInteger(response, "serverTime");
            } else if (Helpers.isTrue(Helpers.isEqual(marketType, "swap")))
            {
                response = (this.contractPublicGetPing(query)).join();
                //
                //     {"success":true,"code":"0","data":"1648124374985"}
                //
                return this.safeInteger(response, "data");
            }
            return null;
        });

    }

