    public Object parseCurrency(Object rawCurrency)
    {
        Object id = this.safeString(rawCurrency, "coin");
        Object code = this.safeCurrencyCode(id);
        Object networks = new java.util.HashMap<String, Object>() {{}};
        Object chains = this.safeValue(rawCurrency, "networkList", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(chains)); j++)
        {
            Object chain = Helpers.GetValue(chains, j);
            Object networkId = this.safeString2(chain, "netWork", "network");
            Object network = this.networkIdToCode(networkId, code);
            Helpers.addElementToObject(networks, network, new java.util.HashMap<String, Object>() {{
    put( "info", chain );
    put( "id", networkId );
    put( "network", network );
    put( "active", null );
    put( "deposit", MexcCore.this.safeBool(chain, "depositEnable", false) );
    put( "withdraw", MexcCore.this.safeBool(chain, "withdrawEnable", false) );
    put( "fee", MexcCore.this.safeNumber(chain, "withdrawFee") );
    put( "precision", null );
    put( "limits", new java.util.HashMap<String, Object>() {{
        put( "withdraw", new java.util.HashMap<String, Object>() {{
            put( "min", MexcCore.this.safeString(chain, "withdrawMin") );
            put( "max", MexcCore.this.safeString(chain, "withdrawMax") );
        }} );
    }} );
    put( "contract", MexcCore.this.safeString(chain, "contract") );
}});
        }
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "info", rawCurrency );
            put( "id", id );
            put( "code", code );
            put( "name", MexcCore.this.safeString(rawCurrency, "name") );
            put( "active", null );
            put( "deposit", null );
            put( "withdraw", null );
            put( "fee", null );
            put( "precision", null );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "type", "crypto" );
            put( "networks", networks );
        }});
    }

    /**
     * @method
     * @name mexc#fetchMarkets
     * @description retrieves data on all markets for mexc
     * @see https://www.mexc.com/api-docs/spot-v3/market-data-endpoints/exchange-information // spot
     * @see https://www.mexc.com/api-docs/futures/market-endpoints/get-contract-info // swap
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.GetValue(this.options, "adjustForTimeDifference")))
            {
                (this.loadTimeDifference()).join();
            }
            Object spotMarketPromise = this.fetchSpotMarkets(parameters);
            Object swapMarketPromise = this.fetchSwapMarkets(parameters);
            var spotMarketswapMarketVariable = (Helpers.promiseAll(new java.util.ArrayList<Object>(java.util.Arrays.asList(spotMarketPromise, swapMarketPromise)))).join();
            var spotMarket = ((java.util.List<Object>) spotMarketswapMarketVariable).get(0);
            var swapMarket = ((java.util.List<Object>) spotMarketswapMarketVariable).get(1);
            return this.arrayConcat(spotMarket, swapMarket);
        });

    }

