    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(ticker, "symbol");
        market = this.safeMarket(marketId, market);
        Object timestamp = null;
        Object bid = null;
        Object ask = null;
        Object bidVolume = null;
        Object askVolume = null;
        Object baseVolume = null;
        Object quoteVolume = null;
        Object open = null;
        Object high = null;
        Object low = null;
        Object changePcnt = null;
        Object changeValue = null;
        Object prevClose = null;
        Object isSwap = this.safeValue(market, "swap");
        // if swap
        if (Helpers.isTrue(Helpers.isTrue(isSwap) || Helpers.isTrue((Helpers.inOp(ticker, "timestamp")))))
        {
            //
            //     {
            //         "symbol": "ETH_USDT",
            //         "lastPrice": 3581.3,
            //         "bid1": 3581.25,
            //         "ask1": 3581.5,
            //         "volume24": 4045530,
            //         "amount24": 141331823.5755,
            //         "holdVol": 5832946,
            //         "lower24Price": 3413.4,
            //         "high24Price": 3588.7,
            //         "riseFallRate": 0.0275,
            //         "riseFallValue": 95.95,
            //         "indexPrice": 3580.7852,
            //         "fairPrice": 3581.08,
            //         "fundingRate": 0.000063,
            //         "maxBidPrice": 3938.85,
            //         "minAskPrice": 3222.7,
            //         "timestamp": 1634162885016
            //     }
            //
            timestamp = this.safeInteger(ticker, "timestamp");
            bid = this.safeString(ticker, "bid1");
            ask = this.safeString(ticker, "ask1");
            baseVolume = this.safeString(ticker, "volume24");
            quoteVolume = this.safeString(ticker, "amount24");
            high = this.safeString(ticker, "high24Price");
            low = this.safeString(ticker, "lower24Price");
            changeValue = this.safeString(ticker, "riseFallValue");
            changePcnt = this.safeString(ticker, "riseFallRate");
            changePcnt = Precise.stringMul(changePcnt, "100");
        } else
        {
            //
            //     {
            //         "symbol": "BTCUSDT",
            //         "priceChange": "184.34",
            //         "priceChangePercent": "0.00400048",
            //         "prevClosePrice": "46079.37",
            //         "lastPrice": "46263.71",
            //         "lastQty": "",
            //         "bidPrice": "46260.38",
            //         "bidQty": "",
            //         "askPrice": "46260.41",
            //         "askQty": "",
            //         "openPrice": "46079.37",
            //         "highPrice": "47550.01",
            //         "lowPrice": "45555.5",
            //         "volume": "1732.461487",
            //         "quoteVolume": null,
            //         "openTime": 1641349500000,
            //         "closeTime": 1641349582808,
            //         "count": null
            //     }
            //
            timestamp = this.safeInteger(ticker, "closeTime");
            bid = this.safeString(ticker, "bidPrice");
            ask = this.safeString(ticker, "askPrice");
            bidVolume = this.safeString(ticker, "bidQty");
            askVolume = this.safeString(ticker, "askQty");
            if (Helpers.isTrue(Precise.stringEq(bidVolume, "0")))
            {
                bidVolume = null;
            }
            if (Helpers.isTrue(Precise.stringEq(askVolume, "0")))
            {
                askVolume = null;
            }
            baseVolume = this.safeString(ticker, "volume");
            quoteVolume = this.safeString(ticker, "quoteVolume");
            open = this.safeString(ticker, "openPrice");
            high = this.safeString(ticker, "highPrice");
            low = this.safeString(ticker, "lowPrice");
            prevClose = this.safeString(ticker, "prevClosePrice");
            changeValue = this.safeString(ticker, "priceChange");
            changePcnt = this.safeString(ticker, "priceChangePercent");
            changePcnt = Precise.stringMul(changePcnt, "100");
        }
        final Object finalMarket = market;
        final Object finalTimestamp = timestamp;
        final Object finalOpen = open;
        final Object finalHigh = high;
        final Object finalLow = low;
        final Object finalBid = bid;
        final Object finalBidVolume = bidVolume;
        final Object finalAsk = ask;
        final Object finalAskVolume = askVolume;
        final Object finalPrevClose = prevClose;
        final Object finalChangeValue = changeValue;
        final Object finalChangePcnt = changePcnt;
        final Object finalBaseVolume = baseVolume;
        final Object finalQuoteVolume = quoteVolume;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "timestamp", finalTimestamp );
            put( "datetime", MexcCore.this.iso8601(finalTimestamp) );
            put( "open", finalOpen );
            put( "high", finalHigh );
            put( "low", finalLow );
            put( "close", MexcCore.this.safeString(ticker, "lastPrice") );
            put( "bid", finalBid );
            put( "bidVolume", finalBidVolume );
            put( "ask", finalAsk );
            put( "askVolume", finalAskVolume );
            put( "vwap", null );
            put( "previousClose", finalPrevClose );
            put( "change", finalChangeValue );
            put( "percentage", finalChangePcnt );
            put( "average", null );
            put( "baseVolume", finalBaseVolume );
            put( "quoteVolume", finalQuoteVolume );
            put( "info", ticker );
        }}, market);
    }

    /**
     * @method
     * @name mexc#fetchBidsAsks
     * @description fetches the bid and ask price and volume for multiple markets
     * @see https://www.mexc.com/api-docs/spot-v3/market-data-endpoints/symbol-order-book-ticker
     * @param {string[]|undefined} symbols unified symbols of the markets to fetch the bids and asks for, all markets are returned if not assigned
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [ticker structures]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchBidsAsks(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = null;
            Object isSingularMarket = false;
            if (Helpers.isTrue(!Helpers.isEqual(symbols, null)))
            {
                Object length = Helpers.getArrayLength(symbols);
                isSingularMarket = Helpers.isEqual(length, 1);
                market = this.market(Helpers.GetValue(symbols, 0));
            }
            var marketTypequeryVariable = this.handleMarketTypeAndParams("fetchBidsAsks", market, parameters);
            var marketType = ((java.util.List<Object>) marketTypequeryVariable).get(0);
            var query = ((java.util.List<Object>) marketTypequeryVariable).get(1);
            Object tickers = null;
            if (Helpers.isTrue(Helpers.isEqual(marketType, "spot")))
            {
                tickers = (this.spotPublicGetTickerBookTicker(query)).join();
            } else if (Helpers.isTrue(Helpers.isEqual(marketType, "swap")))
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(this.id, " fetchBidsAsks() is not available for "), marketType), " markets")) ;
            }
            // when it's single symbol request, the returned structure is different (singular object) for both spot & swap, thus we need to wrap inside array
            if (Helpers.isTrue(isSingularMarket))
            {
                tickers = new java.util.ArrayList<Object>(java.util.Arrays.asList(tickers));
            }
            return this.parseTickers(tickers, symbols);
        });

    }

    /**
     * @method
     * @name mexc#createMarketBuyOrderWithCost
     * @description create a market buy order by providing the symbol and cost
     * @see https://www.mexc.com/api-docs/spot-v3/spot-account-trade/new-order
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {float} cost how much you want to trade in units of the quote currency
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createMarketBuyOrderWithCost(Object symbol, Object cost, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            if (!Helpers.isTrue(Helpers.GetValue(market, "spot")))
            {
                throw new NotSupported((String)Helpers.add(this.id, " createMarketBuyOrderWithCost() supports spot orders only")) ;
            }
            Object req = new java.util.HashMap<String, Object>() {{
                put( "cost", cost );
            }};
            return (this.createOrder(symbol, "market", "buy", 0, null, this.extend(req, parameters))).join();
        });

    }

