    public Object parseFundingRate(Object contract, Object... optionalArgs)
    {
        //
        //     {
        //         "symbol": "BTC_USDT",
        //         "fundingRate": 0.000014,
        //         "maxFundingRate": 0.003,
        //         "minFundingRate": -0.003,
        //         "collectCycle": 8,
        //         "nextSettleTime": 1643241600000,
        //         "timestamp": 1643240373359
        //     }
        //
        // watchFundingRate
        //
        //     {
        //         "symbol": "BTC_USDT",
        //         "rate": -0.000021,
        //         "nextSettleTime": 1771084800000
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object nextFundingRate = this.safeNumber2(contract, "fundingRate", "rate");
        Object nextFundingTimestamp = this.safeInteger(contract, "nextSettleTime");
        Object marketId = this.safeString(contract, "symbol");
        Object symbol = this.safeSymbol(marketId, market, null, "contract");
        Object timestamp = this.safeInteger(contract, "timestamp");
        Object interval = this.safeString(contract, "collectCycle");
        Object intervalString = null;
        if (Helpers.isTrue(!Helpers.isEqual(interval, null)))
        {
            intervalString = Helpers.add(interval, "h");
        }
        final Object finalIntervalString = intervalString;
        return new java.util.HashMap<String, Object>() {{
            put( "info", contract );
            put( "symbol", symbol );
            put( "markPrice", null );
            put( "indexPrice", null );
            put( "interestRate", null );
            put( "estimatedSettlePrice", null );
            put( "timestamp", timestamp );
            put( "datetime", MexcCore.this.iso8601(timestamp) );
            put( "fundingRate", nextFundingRate );
            put( "fundingTimestamp", nextFundingTimestamp );
            put( "fundingDatetime", MexcCore.this.iso8601(nextFundingTimestamp) );
            put( "nextFundingRate", null );
            put( "nextFundingTimestamp", null );
            put( "nextFundingDatetime", null );
            put( "previousFundingRate", null );
            put( "previousFundingTimestamp", null );
            put( "previousFundingDatetime", null );
            put( "interval", finalIntervalString );
        }};
    }

