    public Object parseMarketLeverageTiers(Object info, Object... optionalArgs)
    {
        //
        //    {
        //        "symbol": "BTC_USDT",
        //        "displayName": "BTC_USDT永续",
        //        "displayNameEn": "BTC_USDT SWAP",
        //        "positionOpenType": 3,
        //        "baseCoin": "BTC",
        //        "quoteCoin": "USDT",
        //        "settleCoin": "USDT",
        //        "contractSize": 0.0001,
        //        "minLeverage": 1,
        //        "maxLeverage": 125,
        //        "priceScale": 2,
        //        "volScale": 0,
        //        "amountScale": 4,
        //        "priceUnit": 0.5,
        //        "volUnit": 1,
        //        "minVol": 1,
        //        "maxVol": 1000000,
        //        "bidLimitPriceRate": 0.1,
        //        "askLimitPriceRate": 0.1,
        //        "takerFeeRate": 0.0006,
        //        "makerFeeRate": 0.0002,
        //        "maintenanceMarginRate": 0.004,
        //        "initialMarginRate": 0.008,
        //        "riskBaseVol": 10000,
        //        "riskIncrVol": 200000,
        //        "riskIncrMmr": 0.004,
        //        "riskIncrImr": 0.004,
        //        "riskLevelLimit": 5,
        //        "priceCoefficientVariation": 0.1,
        //        "indexOrigin": ["BINANCE","GATEIO","HUOBI","MXC"],
        //        "state": 0, // 0 enabled, 1 delivery, 2 completed, 3 offline, 4 pause
        //        "isNew": false,
        //        "isHot": true,
        //        "isHidden": false
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(info, "symbol");
        Object maintenanceMarginRate = this.safeString(info, "maintenanceMarginRate");
        Object initialMarginRate = this.safeString(info, "initialMarginRate");
        Object maxVol = this.safeString(info, "maxVol");
        Object riskIncrVol = this.safeString(info, "riskIncrVol");
        Object riskIncrMmr = this.safeString(info, "riskIncrMmr");
        Object riskIncrImr = this.safeString(info, "riskIncrImr");
        Object floor = "0";
        Object tiers = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        Object quoteId = this.safeString(info, "quoteCoin");
        if (Helpers.isTrue(Helpers.isEqual(riskIncrVol, "0")))
        {
            return new java.util.ArrayList<Object>(java.util.Arrays.asList(new java.util.HashMap<String, Object>() {{
    put( "tier", 0 );
    put( "symbol", MexcCore.this.safeSymbol(marketId, market, null, "contract") );
    put( "currency", MexcCore.this.safeCurrencyCode(quoteId) );
    put( "minNotional", null );
    put( "maxNotional", null );
    put( "maintenanceMarginRate", null );
    put( "maxLeverage", MexcCore.this.safeNumber(info, "maxLeverage") );
    put( "info", info );
}}));
        }
        while (Precise.stringLt(floor, maxVol))
        {
            Object cap = Precise.stringAdd(floor, riskIncrVol);
            Object minNotional = this.parseNumber(floor);
            Object mainMarginRate = this.parseNumber(maintenanceMarginRate);
            Object maxLev = this.parseNumber(Precise.stringDiv("1", initialMarginRate));
final Object finalRiskIncrVol = riskIncrVol;
                        ((java.util.List<Object>)tiers).add(new java.util.HashMap<String, Object>() {{
                put( "tier", MexcCore.this.parseNumber(Precise.stringDiv(cap, finalRiskIncrVol)) );
                put( "symbol", MexcCore.this.safeSymbol(marketId, market, null, "contract") );
                put( "currency", MexcCore.this.safeCurrencyCode(quoteId) );
                put( "minNotional", minNotional );
                put( "maxNotional", MexcCore.this.parseNumber(cap) );
                put( "maintenanceMarginRate", mainMarginRate );
                put( "maxLeverage", maxLev );
                put( "info", info );
            }});
            initialMarginRate = Precise.stringAdd(initialMarginRate, riskIncrImr);
            maintenanceMarginRate = Precise.stringAdd(maintenanceMarginRate, riskIncrMmr);
            floor = ((String)cap);
        }
        return tiers;
    }

