    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchDeposits
        //
        // {
        //     "amount": "10",
        //     "coin": "USDC-TRX",
        //     "network": "TRX",
        //     "status": "5",
        //     "address": "TSMcEDDvkqY9dz8RkFnrS86U59GwEZjfvh",
        //     "txId": "51a8f49e6f03f2c056e71fe3291aa65e1032880be855b65cecd0595a1b8af95b:0",
        //     "insertTime": "1664805021000",
        //     "unlockConfirm": "200",
        //     "confirmTimes": "203",
        //     "memo": "xxyy1122",
        //     "transHash": "51a8f49e6f03f2c056e71fe3291aa65e1032880be855b65cecd0595a1b8af95b",
        //     "updateTime": "1664805621000",
        //     "netWork: "TRX"
        // }
        //
        // fetchWithdrawals
        //
        // {
        //     "id": "adcd1c8322154de691b815eedcd10c42",
        //     "txId": "0xc8c918cd69b2246db493ef6225a72ffdc664f15b08da3e25c6879b271d05e9d0:0",
        //     "coin": "USDC-MATIC",
        //     "network": "MATIC",
        //     "address": "0xeE6C7a415995312ED52c53a0f8f03e165e0A5D62",
        //     "amount": "2",
        //     "transferType": "0",
        //     "status": "7",
        //     "transactionFee": "1",
        //     "confirmNo": null,
        //     "applyTime": "1664882739000",
        //     "remark": "",
        //     "memo": null,
        //     "explorerUrl": "https://etherscan.io/tx/0xc8c918cd69b2246db493ef6225a72ffdc664f15b08da3e25c6879b271d05e9d0",
        //     "transHash": "0xc8c918cd69b2246db493ef6225a72ffdc664f15b08da3e25c6879b271d05e9d0",
        //     "updateTime": "1664882799000",
        //     "netWork: "MATIC"
        //   }
        //
        // withdraw
        //
        //     {
        //         "id":"25fb2831fb6d4fc7aa4094612a26c81d"
        //     }
        //
        // internal withdraw (aka internal-transfer)
        //
        //     {
        //         "tranId":"ad36f0e9c9a24ae794b36fa4f152e471"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString2(transaction, "id", "tranId");
        Object type = ((Helpers.isTrue((Helpers.isEqual(id, null))))) ? "deposit" : "withdrawal";
        Object timestamp = this.safeInteger2(transaction, "insertTime", "applyTime");
        Object updated = this.safeInteger(transaction, "updateTime");
        Object currencyId = null;
        Object currencyWithNetwork = this.safeString(transaction, "coin");
        if (Helpers.isTrue(!Helpers.isEqual(currencyWithNetwork, null)))
        {
            currencyId = Helpers.GetValue(Helpers.split(currencyWithNetwork, "-"), 0);
        }
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object network = null;
        Object rawNetwork = this.safeString(transaction, "network");
        if (Helpers.isTrue(!Helpers.isEqual(rawNetwork, null)))
        {
            network = this.networkIdToCode(rawNetwork, code);
        }
        Object status = this.parseTransactionStatusByType(this.safeString(transaction, "status"), type);
        Object amountString = this.safeString(transaction, "amount");
        Object address = this.safeString(transaction, "address");
        Object txid = this.safeString2(transaction, "transHash", "txId");
        Object fee = null;
        Object feeCostString = this.safeString(transaction, "transactionFee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            final Object finalFeeCostString = feeCostString;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", MexcCore.this.parseNumber(finalFeeCostString) );
                put( "currency", code );
            }};
        }
        if (Helpers.isTrue(Helpers.isEqual(type, "withdrawal")))
        {
            // mexc withdrawal amount includes the fee
            amountString = Precise.stringSub(amountString, feeCostString);
        }
        final Object finalId = id;
        final Object finalNetwork = network;
        final Object finalType = type;
        final Object finalAmountString = amountString;
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", finalId );
            put( "txid", txid );
            put( "timestamp", timestamp );
            put( "datetime", MexcCore.this.iso8601(timestamp) );
            put( "network", finalNetwork );
            put( "address", address );
            put( "addressTo", address );
            put( "addressFrom", null );
            put( "tag", MexcCore.this.safeString(transaction, "memo") );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", finalType );
            put( "amount", MexcCore.this.parseNumber(finalAmountString) );
            put( "currency", code );
            put( "status", status );
            put( "updated", updated );
            put( "comment", MexcCore.this.safeString(transaction, "remark") );
            put( "internal", null );
            put( "fee", finalFee );
        }};
    }

    public Object parseTransactionStatusByType(Object status, Object... optionalArgs)
    {
        Object type = Helpers.getArg(optionalArgs, 0, null);
        Object statusesByType = new java.util.HashMap<String, Object>() {{
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "1", "failed" );
                put( "2", "pending" );
                put( "3", "pending" );
                put( "4", "pending" );
                put( "5", "ok" );
                put( "6", "pending" );
                put( "7", "failed" );
            }} );
            put( "withdrawal", new java.util.HashMap<String, Object>() {{
                put( "1", "pending" );
                put( "2", "pending" );
                put( "3", "pending" );
                put( "4", "pending" );
                put( "5", "pending" );
                put( "6", "pending" );
                put( "7", "ok" );
                put( "8", "failed" );
                put( "9", "canceled" );
                put( "10", "pending" );
            }} );
        }};
        Object statuses = this.safeValue(statusesByType, ((String)type), new java.util.HashMap<String, Object>() {{}});
        return this.safeString(statuses, status, status);
    }

